const body = $input.first().json;
const type = body.investor_type?.toLowerCase() || '';
const investorType = type.includes('accredited') ? 'Accredited Investor' : type.includes('lender') ? 'Private Lender' : type.includes('jv') ? 'JV Partner' : 'Prospect';
return [{ json: { ...body, investment_type: investorType, lead_type: 'Investor', status: 'New', preferred_return: body.preferred_return || 0.08 } }];
